import React from 'react';
import { motion } from 'framer-motion';
import { ShoppingCart, Flame } from 'lucide-react';
import Button from './Button';
import useCartStore from '../store/cartStore';

const MealCard = ({ meal }) => {
  const addItem = useCartStore((state) => state.addItem);

  const handleAddToCart = () => {
    addItem(meal);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      whileHover={{ y: -10 }}
      className="bg-white rounded-2xl overflow-hidden shadow-premium hover:shadow-hover transition-all duration-300"
    >
      {/* Image Container */}
      <div className="relative h-48 bg-neutral-bg overflow-hidden">
        <motion.img
          src={meal.image || 'https://via.placeholder.com/300x200?text=Meal'}
          alt={meal.name}
          className="w-full h-full object-cover"
          whileHover={{ scale: 1.1 }}
          transition={{ duration: 0.3 }}
        />
        <div className="absolute top-3 right-3 bg-primary text-white px-3 py-1 rounded-full text-sm font-semibold flex items-center gap-1">
          <Flame size={14} />
          {meal.calories}
        </div>
      </div>

      {/* Content */}
      <div className="p-4">
        <h3 className="font-poppins font-bold text-lg text-dark-text mb-2 line-clamp-2">
          {meal.name}
        </h3>
        
        <p className="text-gray-600 text-sm mb-3 line-clamp-2">
          {meal.description}
        </p>

        <div className="flex items-center justify-between mb-4">
          <span className="text-2xl font-poppins font-bold text-primary">
            ${meal.price}
          </span>
          <span className="text-xs bg-neutral-bg text-dark-text px-2 py-1 rounded-lg">
            {meal.category}
          </span>
        </div>

        <Button
          variant="primary"
          size="md"
          className="w-full flex items-center justify-center gap-2"
          onClick={handleAddToCart}
        >
          <ShoppingCart size={18} />
          Add to Cart
        </Button>
      </div>
    </motion.div>
  );
};

export default MealCard;
